import type { CardConfig } from "../contracts/types";

export function migrateSavedConfigVacuumLegacy(config: CardConfig): boolean {
  if (config.type === "action" && config.sensor === "vacuum.start") {
    config.type = "vacuum";
    config.sensor = "start_stop";
    config.unit = "";
    config.precision = "";
    config.options = "";
    config.icon_on = "Auto";
    return true;
  }
  if (config.type === "action" && config.sensor === "vacuum.return_to_base") {
    config.type = "vacuum";
    config.sensor = "dock";
    config.unit = "";
    config.precision = "";
    config.options = "";
    config.icon_on = "Auto";
    return true;
  }
  return false;
}

const SAVED_CONFIG_VACUUM_SENSOR_VALUES = new Set<string>(["status", "start_stop", "dock", "pause_resume", "clean_spot", "locate", "clean_area"]);
const SAVED_CONFIG_VACUUM_SENSOR_ALIASES: Readonly<Record<string, string>> = {"vacuum.start": "start_stop", "vacuum.return_to_base": "dock"};

export function normalizeSavedConfigVacuumSensor(sensor: string): string {
  sensor = SAVED_CONFIG_VACUUM_SENSOR_ALIASES[sensor] || sensor;
  return SAVED_CONFIG_VACUUM_SENSOR_VALUES.has(sensor) ? sensor : "start_stop";
}

export function normalizeSavedConfigVacuumIconOn(_iconOn: string): string {
  return "Auto";
}

export function normalizeSavedConfigVacuumPrecision(_precision: string): string {
  return "";
}

export function normalizeSavedConfigVacuumOptions(_options: string): string {
  return "";
}
